import{c as s,Q as i,j as a,m as t}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"Visual regression baselines — regeneration workflow","description":"","frontmatter":{},"headers":[],"relativePath":"guides/visual-regression-baselines.md","filePath":"guides/visual-regression-baselines.md"}'),n={name:"guides/visual-regression-baselines.md"};function o(l,e,r,h,d,c){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="visual-regression-baselines-—-regeneration-workflow" tabindex="-1">Visual regression baselines — regeneration workflow <a class="header-anchor" href="#visual-regression-baselines-—-regeneration-workflow" aria-label="Permalink to &quot;Visual regression baselines — regeneration workflow&quot;">​</a></h1><p><code>tests/e2e/visual.spec.ts</code> is a small pilot suite that compares element-scoped screenshots of three layout-stable surfaces (<code>/credits</code> header, <code>/library</code> header, <code>/science</code> tab strip) against committed baselines. Six baselines per platform (3 surfaces × 2 viewports), times two platforms (darwin + linux) = <strong>12 PNGs</strong> in <code>tests/e2e/visual.spec.ts-snapshots/</code>.</p><p>The two platforms exist because <strong>Playwright suffixes baseline filenames with the host OS</strong> (<code>*-darwin.png</code> on macOS, <code>*-linux.png</code> on the GitHub Actions ubuntu-latest runner). A baseline generated on darwin will be flagged as &quot;missing baseline&quot; on linux, and vice versa — Chromium&#39;s font hinting and sub-pixel rendering produce different PNG bytes on different OSes even for identical DOM.</p><p>This guide is the recipe for regenerating both sets in lockstep whenever a covered layout changes.</p><hr><h2 id="when-to-regenerate" tabindex="-1">When to regenerate <a class="header-anchor" href="#when-to-regenerate" aria-label="Permalink to &quot;When to regenerate&quot;">​</a></h2><p>You <strong>must</strong> regenerate both sets together when any of these change:</p><ul><li>A CSS rule that affects the <code>section.credits &gt; header.head</code> element on <code>/credits</code>.</li><li>A CSS rule that affects the <code>section.library &gt; header.head</code> element on <code>/library</code>.</li><li>The <code>/science</code> tab strip layout (any of <code>main</code>, <code>.science-page</code>, <code>nav.tabs</code> on the landing).</li><li>A font (file or <code>font-display</code> rule) that the affected pages render.</li><li>A token in <code>src/styles/tokens.css</code> that any of the above consume.</li></ul><p>If you change the page&#39;s content (e.g. add a new section ID, rename a tab) you might also need to update the <code>selector</code> in <code>STABLE_ELEMENTS</code> at the top of <code>visual.spec.ts</code> — re-baselining isn&#39;t enough on its own.</p><p>You <strong>must NOT</strong> regenerate baselines as a way to silence a failing test. If <code>visual.spec</code> fails on a PR, that&#39;s the test doing its job — find the unintended layout change first.</p><hr><h2 id="regenerating-darwin-baselines-host" tabindex="-1">Regenerating darwin baselines (host) <a class="header-anchor" href="#regenerating-darwin-baselines-host" aria-label="Permalink to &quot;Regenerating darwin baselines (host)&quot;">​</a></h2><p>Run on your local macOS dev machine:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/e2e/visual.spec.ts</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --update-snapshots</span></span></code></pre></div><p>This writes the six <code>*-darwin.png</code> files. Confirm with <code>git status tests/e2e/visual.spec.ts-snapshots/</code> — you should see 6 modified files.</p><p>If you see ZERO modified files after running, the layout you changed isn&#39;t covered by <code>STABLE_ELEMENTS</code> (so visual.spec didn&#39;t notice the change). Either widen the selectors or pick a different verification approach.</p><hr><h2 id="regenerating-linux-baselines-docker" tabindex="-1">Regenerating linux baselines (Docker) <a class="header-anchor" href="#regenerating-linux-baselines-docker" aria-label="Permalink to &quot;Regenerating linux baselines (Docker)&quot;">​</a></h2><p>Requires the Docker daemon to be running (Docker Desktop on macOS, or <code>dockerd</code> on Linux). The image is <strong>~1.2 GB</strong> on first pull; subsequent runs are cached.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> regen-visual-baselines-linux</span></span></code></pre></div><p>(Or directly: <code>./scripts/regenerate-visual-baselines-linux.sh</code>.)</p><p>The script:</p><ol><li>Pulls <code>mcr.microsoft.com/playwright:v${PLAYWRIGHT_VERSION}-noble</code> — pinned to the exact <code>@playwright/test</code> version in <code>package.json</code>, so the bundled Chromium matches CI.</li><li>Mounts the repo at <code>/repo</code> and a host-side <code>.linux-node-modules/</code> (gitignored) at <code>/repo/node_modules</code> — this OVERLAYS your darwin <code>node_modules</code> so the container sees Linux-native binaries (esbuild, paraglide, etc.) and the host install stays untouched.</li><li>Runs <code>npm ci --include=optional</code> on first invocation (one-time, ~60 s) to populate <code>.linux-node-modules/</code>.</li><li>Runs <code>npm run build</code> (vite preview needs <code>build/</code>).</li><li>Runs <code>npx playwright test tests/e2e/visual.spec.ts --workers=1 --update-snapshots</code>.</li></ol><p>After the script exits, <code>git status tests/e2e/visual.spec.ts-snapshots/</code> should show six new or modified <code>*-linux.png</code> files.</p><h3 id="why-not-just-generate-linux-baselines-in-a-gh-actions-workflow" tabindex="-1">Why not just generate linux baselines in a GH Actions workflow? <a class="header-anchor" href="#why-not-just-generate-linux-baselines-in-a-gh-actions-workflow" aria-label="Permalink to &quot;Why not just generate linux baselines in a GH Actions workflow?&quot;">​</a></h3><p>You can — <code>workflow_dispatch</code> an <code>--update-snapshots</code> run, then commit the artifact. But the local Docker path is faster (no PR cycle), produces the same bytes as CI (the Docker image is the same one GH Actions uses for the playwright action), and means baseline regeneration doesn&#39;t need a special workflow. The script is the cheapest abstraction over <code>docker run + bind-mount</code>.</p><hr><h2 id="verify-both-sets-pass-before-pushing" tabindex="-1">Verify both sets pass before pushing <a class="header-anchor" href="#verify-both-sets-pass-before-pushing" aria-label="Permalink to &quot;Verify both sets pass before pushing&quot;">​</a></h2><p>After regenerating:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Darwin sanity (fast — ~10 s)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/e2e/visual.spec.ts</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workers=1</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Linux sanity (slower — ~30 s after first pull because docker)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --ipc=host</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">):$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">id</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)&quot;:/repo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)/.linux-node-modules&quot;:/repo/node_modules</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -w</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /repo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> CI=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HOME=/tmp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm_config_cache=/tmp/.npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  mcr.microsoft.com/playwright:v1.60.0-noble</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/e2e/visual.spec.ts</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --workers=1</span></span></code></pre></div><p>Both should show <code>6 passed</code>. If either set fails, the regeneration didn&#39;t take — investigate before pushing.</p><hr><h2 id="commit-conventions" tabindex="-1">Commit conventions <a class="header-anchor" href="#commit-conventions" aria-label="Permalink to &quot;Commit conventions&quot;">​</a></h2><ul><li>Always commit <strong>both</strong> <code>*-darwin.png</code> AND <code>*-linux.png</code> in the <strong>same</strong> change. Mixing platforms across commits means a future bisect can land on a half-baselined state that fails CI on linux but passes locally on darwin (or vice versa).</li><li>Include the <em>why</em> in the commit message: which CSS/layout change is being baselined. &quot;regenerate baselines&quot; with no context rots when the next regeneration happens 6 months later.</li><li>Don&#39;t commit baselines for OSes you didn&#39;t actually run on. If you only have a darwin machine, don&#39;t manually fabricate <code>*-linux.png</code> files — use the Docker script.</li></ul><hr><h2 id="failure-modes-seen-so-far" tabindex="-1">Failure modes seen so far <a class="header-anchor" href="#failure-modes-seen-so-far" aria-label="Permalink to &quot;Failure modes seen so far&quot;">​</a></h2><h3 id="npm-ci-fails-with-eacces-writing-to-npm" tabindex="-1"><code>npm ci</code> fails with <code>EACCES</code> writing to <code>/.npm</code> <a class="header-anchor" href="#npm-ci-fails-with-eacces-writing-to-npm" aria-label="Permalink to &quot;`npm ci` fails with `EACCES` writing to `/.npm`&quot;">​</a></h3><p>The Playwright Docker image creates a default <code>~/.npm</code> owned by root. If <code>--user $(id -u):$(id -g)</code> is set (which we do, so PNGs aren&#39;t root-owned), npm can&#39;t write the cache. <strong>Fix:</strong> the script sets <code>HOME=/tmp</code> + <code>npm_config_cache=/tmp/.npm</code> to redirect both. Don&#39;t remove those env vars.</p><h3 id="esbuild-crashes-with-you-installed-esbuild-for-another-platform" tabindex="-1"><code>esbuild</code> crashes with &quot;you installed esbuild for another platform&quot; <a class="header-anchor" href="#esbuild-crashes-with-you-installed-esbuild-for-another-platform" aria-label="Permalink to &quot;`esbuild` crashes with &quot;you installed esbuild for another platform&quot;&quot;">​</a></h3><p>Happens when the container can see darwin native binaries from the host&#39;s <code>node_modules</code>. <strong>Fix:</strong> the script overlays <code>.linux-node-modules/</code> at <code>/repo/node_modules</code> so the container has its own Linux install. If you see this error, check the overlay mount is actually there in the <code>docker run</code> invocation.</p><h3 id="baselines-change-unexpectedly-on-every-regeneration" tabindex="-1">Baselines change unexpectedly on every regeneration <a class="header-anchor" href="#baselines-change-unexpectedly-on-every-regeneration" aria-label="Permalink to &quot;Baselines change unexpectedly on every regeneration&quot;">​</a></h3><p>Likely a non-deterministic render — animation that didn&#39;t settle, font that loaded mid-paint, dynamic timestamp on the page. The spec already does <code>requestAnimationFrame ×2</code> to settle fonts; if that&#39;s not enough, the surface isn&#39;t actually &quot;layout-stable&quot; and shouldn&#39;t be in <code>STABLE_ELEMENTS</code>.</p><hr><h2 id="when-ci-says-missing-baseline-anyway" tabindex="-1">When CI says &quot;missing baseline&quot; anyway <a class="header-anchor" href="#when-ci-says-missing-baseline-anyway" aria-label="Permalink to &quot;When CI says &quot;missing baseline&quot; anyway&quot;">​</a></h2><p>The Playwright suffix depends on <code>process.platform</code> at run time, not at write time. If CI is reporting <code>*-linux.png</code> missing for a baseline that visibly exists in <code>tests/e2e/visual.spec.ts-snapshots/</code>, check:</p><ul><li>Is the file actually committed and pushed? <code>git ls-files tests/e2e/visual.spec.ts-snapshots/</code> from the PR head.</li><li>Are you on a different Playwright version? The Docker image tag is pinned to the host <code>package.json</code> version; if you bumped <code>@playwright/test</code> without re-running the script, the image / baselines may have drifted.</li><li>Did a font file or static asset change without a corresponding baseline regeneration? <code>git log -- static/fonts/</code> since the baselines were last committed.</li></ul><hr><h2 id="tracking" tabindex="-1">Tracking <a class="header-anchor" href="#tracking" aria-label="Permalink to &quot;Tracking&quot;">​</a></h2><ul><li>Issue #132 (closed) — initial linux baseline generation and removal of the darwin-only <code>test.skip</code>.</li><li><code>scripts/regenerate-visual-baselines-linux.sh</code> — automation source of truth.</li><li><code>tests/e2e/visual.spec.ts</code> — the spec itself; comment block at the top of the test block points back here.</li></ul>',49)])])}const g=s(n,[["render",o]]);export{u as __pageData,g as default};
